    if k == 0 {
        return n * m
    }
    // Calculate the step in rows and columns
    stepRow := 2*k + 1
    stepCol := 2*k + 1

    // Calculate the number of sensors needed for rows and columns
    sensorsRow := (n + stepRow - 1) / stepRow
    sensorsCol := (m + stepCol - 1) / stepCol

    return sensorsRow * sensorsCol
